import { AnimatePresence } from 'framer-motion';
import { db } from '../firebase/firebase';
import { useOutletContext } from 'react-router-dom';
import SearchIcon from '@mui/icons-material/Search';
import CheckCircleOutlineIcon from '@mui/icons-material/CheckCircleOutline';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import KeyboardArrowDownIcon from '@mui/icons-material/KeyboardArrowDown';
import '../styles/DsaPractice.css';

// --- Static Problem Data ---
const dsaTopics = [
    {
        topicId: 'arrays',
        topicName: 'Arrays',
        problems: [
            { id: 'two-sum', title: 'Two Sum', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/two-sum/', companies: ['Google', 'Amazon', 'Microsoft', 'Meta', 'Apple'] },
            { id: 'best-time-to-buy-and-sell-stock', title: 'Best Time to Buy and Sell Stock', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/best-time-to-buy-and-sell-stock/', companies: ['Amazon', 'Microsoft', 'Meta'] },
            { id: 'maximum-subarray', title: 'Maximum Subarray', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/maximum-subarray/', companies: ['Google', 'Microsoft', 'Apple'] },
            { id: 'product-of-array-except-self', title: 'Product of Array Except Self', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/product-of-array-except-self/', companies: ['Amazon', 'Meta', 'Netflix'] },
            { id: 'trapping-rain-water', title: 'Trapping Rain Water', difficulty: 'Hard', leetcodeUrl: 'https://leetcode.com/problems/trapping-rain-water/', companies: ['Google', 'Amazon', 'Apple'] },
        ]
    },
    {
        topicId: 'strings',
        topicName: 'Strings',
        problems: [
            { id: 'valid-anagram', title: 'Valid Anagram', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/valid-anagram/', companies: ['Google', 'Amazon', 'Microsoft'] },
            { id: 'valid-palindrome', title: 'Valid Palindrome', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/valid-palindrome/', companies: ['Meta', 'Apple'] },
            { id: 'longest-substring-without-repeating-characters', title: 'Longest Substring Without Repeating Characters', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/longest-substring-without-repeating-characters/', companies: ['Amazon', 'Netflix'] },
            { id: 'longest-repeating-character-replacement', title: 'Longest Repeating Character Replacement', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/longest-repeating-character-replacement/', companies: ['Google', 'Uber'] },
            { id: 'minimum-window-substring', title: 'Minimum Window Substring', difficulty: 'Hard', leetcodeUrl: 'https://leetcode.com/problems/minimum-window-substring/', companies: ['Meta', 'Amazon'] },
        ]
    },
    {
        topicId: 'linked-lists',
        topicName: 'Linked Lists',
        problems: [
            { id: 'reverse-linked-list', title: 'Reverse Linked List', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/reverse-linked-list/', companies: ['Amazon', 'Microsoft', 'Apple'] },
            { id: 'linked-list-cycle', title: 'Linked List Cycle', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/linked-list-cycle/', companies: ['Google', 'Amazon'] },
            { id: 'merge-two-sorted-lists', title: 'Merge Two Sorted Lists', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/merge-two-sorted-lists/', companies: ['Amazon', 'Microsoft'] },
            { id: 'add-two-numbers', title: 'Add Two Numbers', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/add-two-numbers/', companies: ['Amazon', 'Google'] },
            { id: 'lru-cache', title: 'LRU Cache', difficulty: 'Hard', leetcodeUrl: 'https://leetcode.com/problems/lru-cache/', companies: ['Google', 'Amazon', 'Microsoft'] },
        ]
    },
    {
        topicId: 'dynamic-programming',
        topicName: 'Dynamic Programming',
        problems: [
            { id: 'climbing-stairs', title: 'Climbing Stairs', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/climbing-stairs/', companies: ['Amazon', 'Microsoft'] },
            { id: 'house-robber', title: 'House Robber', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/house-robber/', companies: ['Google', 'Amazon'] },
            { id: 'coin-change', title: 'Coin Change', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/coin-change/', companies: ['Amazon', 'Microsoft'] },
            { id: 'longest-increasing-subsequence', title: 'Longest Increasing Subsequence', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/longest-increasing-subsequence/', companies: ['Google', 'Meta'] },
            { id: 'edit-distance', title: 'Edit Distance', difficulty: 'Hard', leetcodeUrl: 'https://leetcode.com/problems/edit-distance/', companies: ['Google', 'Amazon'] },
        ]
    },
    {
        topicId: 'trees',
        topicName: 'Trees',
        problems: [
            { id: 'maximum-depth-of-binary-tree', title: 'Maximum Depth of Binary Tree', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/maximum-depth-of-binary-tree/', companies: ['Amazon', 'Microsoft'] },
            { id: 'invert-binary-tree', title: 'Invert Binary Tree', difficulty: 'Easy', leetcodeUrl: 'https://leetcode.com/problems/invert-binary-tree/', companies: ['Google'] },
            { id: 'binary-tree-level-order-traversal', title: 'Binary Tree Level Order Traversal', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/binary-tree-level-order-traversal/', companies: ['Amazon', 'Microsoft'] },
            { id: 'validate-binary-search-tree', title: 'Validate Binary Search Tree', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/validate-binary-search-tree/', companies: ['Amazon', 'Meta'] },
            { id: 'serialize-and-deserialize-binary-tree', title: 'Serialize and Deserialize Binary Tree', difficulty: 'Hard', leetcodeUrl: 'https://leetcode.com/problems/serialize-and-deserialize-binary-tree/', companies: ['Amazon', 'Google'] },
        ]
    },
    {
        topicId: 'graphs',
        topicName: 'Graphs',
        problems: [
            { id: 'number-of-islands', title: 'Number of Islands', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/number-of-islands/', companies: ['Amazon', 'Google'] },
            { id: 'clone-graph', title: 'Clone Graph', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/clone-graph/', companies: ['Meta', 'Amazon'] },
            { id: 'course-schedule', title: 'Course Schedule', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/course-schedule/', companies: ['Amazon', 'Microsoft'] },
            { id: 'word-ladder', title: 'Word Ladder', difficulty: 'Hard', leetcodeUrl: 'https://leetcode.com/problems/word-ladder/', companies: ['Amazon', 'Google'] },
            { id: 'cheapest-flights-within-k-stops', title: 'Cheapest Flights Within K Stops', difficulty: 'Medium', leetcodeUrl: 'https://leetcode.com/problems/cheapest-flights-within-k-stops/', companies: ['Amazon', 'Google'] },
        ]
    }
];

const totalProblemsCount = dsaTopics.reduce((acc, topic) => acc + topic.problems.length, 0);

// --- Small helper to map generic company names to logos ---
// Using clearbit logo API or simple text badges as fallback.
const CompanyLogo = ({ company }) => {
    // Map company name to a domain for clearbit
    const domains = {
        'Google': 'google.com',
        'Amazon': 'amazon.com',
        'Microsoft': 'microsoft.com',
        'Meta': 'meta.com',
        'Apple': 'apple.com',
        'Netflix': 'netflix.com',
        'Uber': 'uber.com'
    };

    const domain = domains[company];
    return domain ? (
        <img
            src={`https://logo.clearbit.com/${domain}?size=24`}
            alt={`${company} logo`}
            className="company-logo"
            title={company}
            onError={(e) => { e.target.style.display = 'none' }} // fallback if fails
        />
    ) : (
        <span className="company-badge-fallback">{company}</span>
    );
};

export default function DsaPractice() {
    const { user } = useOutletContext();
    const [progressData, setProgressData] = useState({});
    const [loading, setLoading] = useState(true);
    const [expandedTopics, setExpandedTopics] = useState(
        dsaTopics.reduce((acc, topic) => ({ ...acc, [topic.topicId]: true }), {})
    );
    const [searchQuery, setSearchQuery] = useState('');
    const [difficultyFilter, setDifficultyFilter] = useState('All'); // All, Easy, Medium, Hard

    useEffect(() => {
        const fetchProgress = async () => {
            if (!user?.uid) return;
            try {
                const docRef = doc(db, 'users', user.uid);
                const docSnap = await getDoc(docRef);
                if (docSnap.exists()) {
                    const data = docSnap.data();
                    if (data.dsaPracticeProgress) {
                        setProgressData(data.dsaPracticeProgress);
                    }
                }
            } catch (err) {
                console.error("Error fetching DSA progress:", err);
            } finally {
                setLoading(false);
            }
        };
        fetchProgress();
    }, [user]);

    const handleToggleProblem = async (problemId) => {
        if (!user?.uid) return;

        const isCurrentlySolved = !!progressData[problemId];
        const newSolvedStatus = !isCurrentlySolved;

        // Optimistic UI update
        setProgressData(prev => ({
            ...prev,
            [problemId]: newSolvedStatus
        }));

        try {
            const docRef = doc(db, 'users', user.uid);
            await updateDoc(docRef, {
                [`dsaPracticeProgress.${problemId}`]: newSolvedStatus
            });
        } catch (err) {
            console.error("Error updating DSA progress:", err);
            // Revert on failure
            setProgressData(prev => ({
                ...prev,
                [problemId]: isCurrentlySolved
            }));

            // If the document doesn't have the field or doesn't exist, we might need a general setDoc with merge
            if (err.code === 'not-found' || err.message.includes('No document to update')) {
                const docRef = doc(db, 'users', user.uid);
                await setDoc(docRef, { dsaPracticeProgress: { [problemId]: newSolvedStatus } }, { merge: true });
            }
        }
    };

    const toggleTopic = (topicId) => {
        setExpandedTopics(prev => ({
            ...prev,
            [topicId]: !prev[topicId]
        }));
    };

    const solvedProblemsCount = Object.values(progressData).filter(Boolean).length;
    const progressPercentage = totalProblemsCount === 0 ? 0 : Math.round((solvedProblemsCount / totalProblemsCount) * 100);

    // Filtering logic
    const filteredTopics = dsaTopics.map(topic => {
        const filteredProblems = topic.problems.filter(prob => {
            const matchesSearch = prob.title.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesDifficulty = difficultyFilter === 'All' || prob.difficulty === difficultyFilter;
            return matchesSearch && matchesDifficulty;
        });
        return { ...topic, problems: filteredProblems };
    }).filter(topic => topic.problems.length > 0);

    if (loading) {
        return <div className="dsa-practice-loading">Loading Practice Tracker...</div>;
    }

    return (
        <div className="dsa-practice-container">
            <header className="dsa-header">
                <div className="dsa-header-text">
                    <h1>DSA Practice Tracker</h1>
                    <p>Track your progress and master Data Structures and Algorithms for technical interviews.</p>
                </div>

                <div className="dsa-progress-card">
                    <div className="dsa-progress-header">
                        <h3>DSA Practice Progress</h3>
                        <span>{solvedProblemsCount} / {totalProblemsCount}</span>
                    </div>
                    <div className="dsa-progress-bar-container">
                        <motion.div
                            className="dsa-progress-bar-fill"
                            initial={{ width: 0 }}
                            animate={{ width: `${progressPercentage}%` }}
                            transition={{ duration: 0.8, ease: "easeOut" }}
                        />
                    </div>
                </div>
            </header>

            <div className="dsa-controls">
                <div className="dsa-search-bar">
                    <SearchIcon className="search-icon" />
                    <input
                        type="text"
                        placeholder="Search problems..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                <div className="dsa-filter">
                    <select
                        value={difficultyFilter}
                        onChange={(e) => setDifficultyFilter(e.target.value)}
                        className="difficulty-select"
                    >
                        <option value="All">All Difficulties</option>
                        <option value="Easy">Easy</option>
                        <option value="Medium">Medium</option>
                        <option value="Hard">Hard</option>
                    </select>
                </div>
            </div>

            <div className="dsa-topics-list">
                {filteredTopics.map((topic) => (
                    <div key={topic.topicId} className="dsa-topic-section">
                        <button
                            className="dsa-topic-header"
                            onClick={() => toggleTopic(topic.topicId)}
                        >
                            <h2>{topic.topicName}</h2>
                            <motion.div
                                animate={{ rotate: expandedTopics[topic.topicId] ? 180 : 0 }}
                                transition={{ duration: 0.3 }}
                            >
                                <KeyboardArrowDownIcon />
                            </motion.div>
                        </button>

                        <AnimatePresence>
                            {expandedTopics[topic.topicId] && (
                                <motion.div
                                    className="dsa-topic-content"
                                    initial={{ height: 0, opacity: 0 }}
                                    animate={{ height: 'auto', opacity: 1 }}
                                    exit={{ height: 0, opacity: 0 }}
                                    transition={{ duration: 0.3 }}
                                >
                                    {topic.problems.map((prob) => {
                                        const isSolved = !!progressData[prob.id];
                                        return (
                                            <div key={prob.id} className="dsa-problem-card">
                                                <div className="dsa-problem-left">
                                                    <motion.button
                                                        className={`dsa-checkbox ${isSolved ? 'solved' : ''}`}
                                                        onClick={() => handleToggleProblem(prob.id)}
                                                        whileTap={{ scale: 0.9 }}
                                                    >
                                                        {isSolved ? (
                                                            <motion.div
                                                                initial={{ scale: 0 }}
                                                                animate={{ scale: 1 }}
                                                                transition={{ type: "spring", stiffness: 300, damping: 20 }}
                                                            >
                                                                <CheckCircleIcon className="checked-icon" />
                                                            </motion.div>
                                                        ) : (
                                                            <CheckCircleOutlineIcon className="unchecked-icon" />
                                                        )}
                                                    </motion.button>
                                                    <a href={prob.leetcodeUrl} target="_blank" rel="noopener noreferrer" className="dsa-problem-title">
                                                        {prob.title}
                                                    </a>
                                                </div>

                                                <div className="dsa-problem-center">
                                                    <span className={`difficulty-badge ${prob.difficulty.toLowerCase()}`}>
                                                        {prob.difficulty}
                                                    </span>
                                                </div>

                                                <div className="dsa-problem-right">
                                                    {prob.companies && prob.companies.map((company) => (
                                                        <CompanyLogo key={company} company={company} />
                                                    ))}
                                                </div>
                                            </div>
                                        )
                                    })}
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                ))}

                {filteredTopics.length === 0 && (
                    <div className="dsa-no-results">
                        <p>No problems found matching your criteria.</p>
                    </div>
                )}
            </div>
        </div>
    );
}
